UPDATE tbl_community_post
set Post_View_Count = Post_View_Count + 1
WHERE post_no = #{postNo}

UPDATE TBL_COMMUNITY_POST
SET Post_Title = #{postTitle}, POST_CONTENT = #{postContent}, USER_NICKNAME= #{userNickname}
WHERE POST_NO = #{postNo}

mapper.select:

SELECT * FROM (
SELECT ROWNUM AS RNUM, subquery.*
FROM (
	SELECT tcp.post_no,tcp.user_no, tcp.post_title, tcp.user_nickname, tcp.post_date, 
	(select count(post_like_no) from tbl_post_like tpl where tpl.post_no = tcp.post_no) as like_count
	FROM tbl_community_post tcp
	ORDER BY tcp.post_date DESC			
) subquery
) WHERE RNUM BETWEEN #{startRow} AND #{endRow}


SELECT * FROM(
	SELECT ROWNUM AS rnum, subquery.*
	FROM (
		SELECT tcc.comment_no, tcc.user_no, tcc.user_nickname, tcc.coment_content, tcc.post_date
		FROM tbl_community_comment tcc
		WHERE tcc.post_no = #{postNo}
		ORDER BY tcc.post_date desc ) subquery
	) WHERE rnum between #{startRow} and #{endRow}
